HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>DHG Pharma \u2014 SWOT Analysis 2025</title>\n<script src=\"https://cdn.jsdelivr.net/npm/chart.js@4.4.2/dist/chart.umd.min.js\"></script>\n<style>\n  :root {\n    --green-dark:  #0A5C3A;\n    --green-main:  #0D7A4E;\n    --green-mid:   #1A9960;\n    --green-light: #D6F0E4;\n    --green-pale:  #EBF8F2;\n    --red-main:    #C41E3A;\n    --red-light:   #FAE8EB;\n    --red-pale:    #FDF2F4;\n    --gold:        #E8A020;\n    --gold-light:  #FDF3E0;\n    --text-primary:   #1A1A1A;\n    --text-secondary: #5A6472;\n    --text-muted:     #8A9099;\n    --border:         #E2E8E4;\n    --bg-page:        #F7FAF8;\n    --bg-card:        #FFFFFF;\n    --bg-surface:     #F2F7F4;\n  }\n  * { box-sizing: border-box; margin: 0; padding: 0; }\n  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: var(--bg-page); color: var(--text-primary); line-height: 1.6; }\n\n  /* TOP BAR */\n  .topbar {\n    background: var(--green-main);\n    color: white;\n    padding: 0 2rem;\n    display: flex;\n    align-items: center;\n    justify-content: space-between;\n    height: 56px;\n    position: sticky;\n    top: 0;\n    z-index: 100;\n    box-shadow: 0 2px 8px rgba(13,122,78,0.25);\n  }\n  .topbar-brand { display: flex; align-items: center; gap: 12px; }\n  .topbar-logo {\n    width: 36px; height: 36px; background: white; border-radius: 8px;\n    display: flex; align-items: center; justify-content: center;\n    font-weight: 700; font-size: 13px; color: var(--green-main); letter-spacing: -0.5px;\n  }\n  .topbar-title { font-size: 15px; font-weight: 600; letter-spacing: 0.01em; }\n  .topbar-sub { font-size: 12px; opacity: 0.75; margin-top: 1px; }\n  .topbar-year { font-size: 12px; opacity: 0.65; white-space: nowrap; }\n\n  /* NAV TABS */\n  .nav-wrap { background: white; border-bottom: 1px solid var(--border); position: sticky; top: 56px; z-index: 90; }\n  .nav { max-width: 1100px; margin: 0 auto; padding: 0 2rem; display: flex; gap: 0; overflow-x: auto; }\n  .nav::-webkit-scrollbar { height: 0; }\n  .nav-btn {\n    padding: 14px 18px; font-size: 13px; font-weight: 500; border: none;\n    background: transparent; color: var(--text-secondary); cursor: pointer;\n    border-bottom: 2px solid transparent; white-space: nowrap;\n    transition: color 0.15s, border-color 0.15s;\n  }\n  .nav-btn:hover { color: var(--green-main); }\n  .nav-btn.active { color: var(--green-main); border-bottom-color: var(--green-main); }\n\n  /* LAYOUT */\n  .page { max-width: 1100px; margin: 0 auto; padding: 2.5rem 2rem 4rem; }\n  .section { display: none; }\n  .section.visible { display: block; }\n\n  /* HERO */\n  .hero { margin-bottom: 2.5rem; }\n  .hero-eyebrow { font-size: 11px; font-weight: 600; letter-spacing: 0.1em; text-transform: uppercase; color: var(--green-main); margin-bottom: 10px; display: flex; align-items: center; gap: 8px; }\n  .hero-eyebrow::after { content: ''; flex: 1; height: 1px; background: var(--green-light); }\n  .hero-title { font-size: 34px; font-weight: 700; line-height: 1.2; margin-bottom: 12px; letter-spacing: -0.02em; }\n  .hero-title span { color: var(--green-main); }\n  .hero-body { font-size: 15px; color: var(--text-secondary); max-width: 600px; line-height: 1.7; }\n\n  /* STAT CARDS */\n  .stat-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(150px, 1fr)); gap: 12px; margin-bottom: 2.5rem; }\n  .stat-card { background: white; border: 1px solid var(--border); border-radius: 12px; padding: 16px 18px; }\n  .stat-card.accent { background: var(--green-main); border-color: var(--green-main); }\n  .stat-card.accent .stat-label { color: rgba(255,255,255,0.7); }\n  .stat-card.accent .stat-val { color: white; }\n  .stat-card.accent .stat-note { color: rgba(255,255,255,0.8); }\n  .stat-label { font-size: 11px; font-weight: 600; text-transform: uppercase; letter-spacing: 0.07em; color: var(--text-muted); margin-bottom: 6px; }\n  .stat-val { font-size: 24px; font-weight: 700; color: var(--text-primary); line-height: 1.1; }\n  .stat-note { font-size: 12px; color: var(--green-main); margin-top: 4px; font-weight: 500; }\n\n  /* CHARTS */\n  .charts-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin-bottom: 2.5rem; }\n  .chart-card { background: white; border: 1px solid var(--border); border-radius: 12px; padding: 20px; }\n  .chart-title { font-size: 13px; font-weight: 600; color: var(--text-secondary); text-transform: uppercase; letter-spacing: 0.06em; margin-bottom: 16px; }\n  .chart-wrap { position: relative; height: 200px; }\n  @media (max-width: 700px) { .charts-grid { grid-template-columns: 1fr; } }\n\n  /* SWOT MATRIX */\n  .swot-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 14px; margin-bottom: 2rem; }\n  .swot-card { border-radius: 14px; padding: 1.5rem; border: 1px solid transparent; }\n  .swot-card.s { background: var(--green-pale); border-color: #A8DECA; }\n  .swot-card.w { background: var(--red-pale); border-color: #F0B8C2; }\n  .swot-card.o { background: #EDF7E0; border-color: #B8DFA0; }\n  .swot-card.t { background: var(--gold-light); border-color: #F0D090; }\n  .swot-head { display: flex; align-items: center; gap: 10px; margin-bottom: 14px; }\n  .swot-icon { width: 32px; height: 32px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 15px; flex-shrink: 0; }\n  .s .swot-icon { background: var(--green-main); color: white; }\n  .w .swot-icon { background: var(--red-main); color: white; }\n  .o .swot-icon { background: #3A8A18; color: white; }\n  .t .swot-icon { background: #B07010; color: white; }\n  .swot-label { font-size: 14px; font-weight: 700; }\n  .s .swot-label { color: var(--green-dark); }\n  .w .swot-label { color: #8B1525; }\n  .o .swot-label { color: #2A6010; }\n  .t .swot-label { color: #7A5008; }\n  .swot-item { font-size: 13px; line-height: 1.55; margin-bottom: 10px; padding-left: 14px; border-left: 3px solid; }\n  .s .swot-item { border-color: var(--green-main); color: var(--green-dark); }\n  .w .swot-item { border-color: var(--red-main); color: #6B1020; }\n  .o .swot-item { border-color: #3A8A18; color: #1A4808; }\n  .t .swot-item { border-color: var(--gold); color: #5A3808; }\n  .swot-item strong { font-weight: 600; display: block; margin-bottom: 2px; }\n  @media (max-width: 640px) { .swot-grid { grid-template-columns: 1fr; } }\n\n  /* DETAIL CARDS */\n  .detail-grid { display: grid; gap: 14px; margin-bottom: 2rem; }\n  .detail-card { background: white; border: 1px solid var(--border); border-radius: 12px; padding: 1.5rem; }\n  .detail-head { display: flex; align-items: flex-start; gap: 14px; margin-bottom: 12px; }\n  .detail-num-badge { width: 32px; height: 32px; border-radius: 8px; background: var(--green-pale); color: var(--green-main); font-size: 13px; font-weight: 700; display: flex; align-items: center; justify-content: center; flex-shrink: 0; margin-top: 2px; }\n  .w-section .detail-num-badge { background: var(--red-pale); color: var(--red-main); }\n  .t-section .detail-num-badge { background: var(--gold-light); color: #8A5010; }\n  .detail-title { font-size: 15px; font-weight: 700; margin-bottom: 4px; }\n  .detail-badge { display: inline-flex; align-items: center; gap: 4px; font-size: 11px; font-weight: 600; padding: 2px 10px; border-radius: 999px; }\n  .badge-green { background: var(--green-light); color: var(--green-dark); }\n  .badge-red { background: #FAD0D8; color: #7B1025; }\n  .badge-blue { background: #D8EAFA; color: #1A4C8A; }\n  .badge-amber { background: #FAE8C0; color: #7A4A08; }\n  .detail-body { font-size: 13.5px; color: var(--text-secondary); line-height: 1.7; padding-left: 46px; }\n\n  /* RECOMMENDATIONS */\n  .rec-card { border-left: 4px solid var(--green-main); background: white; border-radius: 0 12px 12px 0; padding: 1.25rem 1.5rem; margin-bottom: 12px; border-top: 1px solid var(--border); border-right: 1px solid var(--border); border-bottom: 1px solid var(--border); }\n  .rec-num { font-size: 11px; font-weight: 700; text-transform: uppercase; letter-spacing: 0.08em; color: var(--green-main); margin-bottom: 6px; }\n  .rec-title { font-size: 15px; font-weight: 700; margin-bottom: 8px; }\n  .rec-body { font-size: 13.5px; color: var(--text-secondary); line-height: 1.7; }\n\n  /* SECTION TITLE */\n  .section-title { font-size: 18px; font-weight: 700; margin-bottom: 1.25rem; }\n  .section-title span { color: var(--green-main); }\n\n  /* INFO BOX */\n  .info-box { background: var(--green-pale); border: 1px solid #A8DECA; border-radius: 10px; padding: 14px 18px; font-size: 13px; color: var(--green-dark); margin-bottom: 1.5rem; line-height: 1.6; }\n  .info-box strong { font-weight: 700; }\n\n  /* PARTNER GRID */\n  .partner-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 12px; margin-top: 1rem; }\n  .partner-card { background: white; border: 1px solid var(--border); border-radius: 10px; padding: 1rem 1.25rem; }\n  .partner-name { font-size: 14px; font-weight: 700; margin-bottom: 6px; color: var(--text-primary); }\n  .partner-body { font-size: 12.5px; color: var(--text-secondary); line-height: 1.6; }\n  @media (max-width: 500px) { .partner-grid { grid-template-columns: 1fr; } }\n\n  /* MARKET BARS */\n  .bar-table { margin-bottom: 1.5rem; }\n  .bar-row { display: flex; align-items: center; gap: 12px; margin-bottom: 10px; }\n  .bar-label { font-size: 12px; color: var(--text-secondary); min-width: 110px; text-align: right; font-weight: 500; }\n  .bar-track { flex: 1; height: 22px; background: var(--bg-surface); border-radius: 5px; overflow: hidden; border: 1px solid var(--border); }\n  .bar-fill { height: 100%; border-radius: 4px; display: flex; align-items: center; padding-left: 10px; font-size: 11px; font-weight: 600; color: white; }\n\n  /* FOOTER */\n  .footer { text-align: center; padding: 2rem 0 0; border-top: 1px solid var(--border); margin-top: 2.5rem; color: var(--text-muted); font-size: 12px; line-height: 2; }\n  .footer strong { color: var(--text-secondary); font-weight: 600; }\n\n  /* DIVIDER */\n  .divider { height: 1px; background: var(--border); margin: 2rem 0; }\n</style>\n</head>\n<body>\n\n<!-- TOP BAR -->\n<div class=\"topbar\">\n  <div class=\"topbar-brand\">\n    <div class=\"topbar-logo\">DHG</div>\n    <div>\n      <div class=\"topbar-title\">DHG Pharma</div>\n      <div class=\"topbar-sub\">SWOT Strategic Analysis 2025</div>\n    </div>\n  </div>\n  <div class=\"topbar-year\">Academic Year 2025 \u00b7 Business English 3</div>\n</div>\n\n<!-- NAV -->\n<div class=\"nav-wrap\">\n  <nav class=\"nav\">\n    <button class=\"nav-btn active\" onclick=\"showSection('overview', this)\">Overview</button>\n    <button class=\"nav-btn\" onclick=\"showSection('swot', this)\">SWOT Matrix</button>\n    <button class=\"nav-btn\" onclick=\"showSection('strengths', this)\">Strengths</button>\n    <button class=\"nav-btn\" onclick=\"showSection('weaknesses', this)\">Weaknesses</button>\n    <button class=\"nav-btn\" onclick=\"showSection('opportunities', this)\">Opportunities</button>\n    <button class=\"nav-btn\" onclick=\"showSection('threats', this)\">Threats</button>\n    <button class=\"nav-btn\" onclick=\"showSection('recommendations', this)\">Recommendations</button>\n  </nav>\n</div>\n\n<div class=\"page\">\n\n  <!-- ======= OVERVIEW ======= -->\n  <div id=\"overview\" class=\"section visible\">\n    <div class=\"hero\">\n      <div class=\"hero-eyebrow\">Strategic Analysis \u00b7 Vietnam Pharmaceutical Industry</div>\n      <div class=\"hero-title\">DHG Pharma<br><span>SWOT Analysis 2025</span></div>\n      <div class=\"hero-body\">Duoc Hau Giang Pharmaceutical \u2014 Vietnam's largest domestic pharmaceutical manufacturer and distributor. A comprehensive analysis of competitive position, market opportunities and strategic risks.</div>\n    </div>\n\n    <div class=\"stat-grid\">\n      <div class=\"stat-card accent\">\n        <div class=\"stat-label\">Net Revenue 2025</div>\n        <div class=\"stat-val\">\u20ab6.14T</div>\n        <div class=\"stat-note\">\u2191 7% year-on-year</div>\n      </div>\n      <div class=\"stat-card\">\n        <div class=\"stat-label\">Net Profit</div>\n        <div class=\"stat-val\">\u20ab852B</div>\n        <div class=\"stat-note\">\u2191 9.4% vs 2024</div>\n      </div>\n      <div class=\"stat-card\">\n        <div class=\"stat-label\">Gross Margin</div>\n        <div class=\"stat-val\">48%</div>\n        <div class=\"stat-note\">\u2191 from 44% in 2024</div>\n      </div>\n      <div class=\"stat-card\">\n        <div class=\"stat-label\">Market Share</div>\n        <div class=\"stat-val\">12\u201315%</div>\n        <div class=\"stat-note\">#1 OTC brand in Vietnam</div>\n      </div>\n      <div class=\"stat-card\">\n        <div class=\"stat-label\">Distribution Points</div>\n        <div class=\"stat-val\">38,000</div>\n        <div class=\"stat-note\">34 GDP-certified branches</div>\n      </div>\n      <div class=\"stat-card\">\n        <div class=\"stat-label\">Employees</div>\n        <div class=\"stat-val\">~3,000</div>\n        <div class=\"stat-note\">63 provinces nationwide</div>\n      </div>\n    </div>\n\n    <div class=\"charts-grid\">\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">Vietnam Pharma Market Size (USD Billion)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartMarket\"></canvas></div>\n      </div>\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">DHG Revenue & Net Profit (\u20ab Billion)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartRevenue\"></canvas></div>\n      </div>\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">DHG Gross Margin Trend (%)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartMargin\"></canvas></div>\n      </div>\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">Revenue Breakdown by Channel 2025</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartChannel\"></canvas></div>\n      </div>\n    </div>\n\n    <div class=\"section-title\">Strategic <span>Partnerships</span></div>\n    <div class=\"info-box\"><strong>Founded in 1974 \u00b7 29 consecutive years as Vietnam's #1 domestic pharmaceutical company.</strong> Headquartered in Can Tho with major manufacturing infrastructure in Hau Giang province. Exports to 20+ countries.</div>\n    <div class=\"partner-grid\">\n      <div class=\"partner-card\">\n        <div class=\"partner-name\">Taisho Pharmaceutical (51% owner)</div>\n        <div class=\"partner-body\">Japan's major OTC pharma company. Provides technology transfer, Japan-GMP standards, R&D collaboration and access to international distribution networks.</div>\n      </div>\n      <div class=\"partner-card\">\n        <div class=\"partner-name\">EU-GMP & Japan-GMP Factories</div>\n        <div class=\"partner-body\">Two internationally certified factories with combined capacity of 8.2 billion units per year \u2014 foundation for contract manufacturing (CMO) and export expansion.</div>\n      </div>\n      <div class=\"partner-card\">\n        <div class=\"partner-name\">ASEAN Export Markets</div>\n        <div class=\"partner-body\">Active presence in Cambodia, Laos, Myanmar and the Philippines. International quality certifications provide a clear competitive edge across Southeast Asia.</div>\n      </div>\n      <div class=\"partner-card\">\n        <div class=\"partner-name\">DHG Pharma Loyalty Club</div>\n        <div class=\"partner-body\">15,244 pharmacy members across Vietnam, reinforcing brand loyalty and creating a direct feedback loop from the distribution network.</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ======= SWOT MATRIX ======= -->\n  <div id=\"swot\" class=\"section\">\n    <div class=\"hero\">\n      <div class=\"hero-eyebrow\">Four-Quadrant Framework</div>\n      <div class=\"hero-title\">SWOT <span>Matrix</span></div>\n      <div class=\"hero-body\">A consolidated view across all four strategic dimensions: internal advantages, areas for improvement, market opportunities, and external risks.</div>\n    </div>\n    <div class=\"swot-grid\">\n      <div class=\"swot-card s\">\n        <div class=\"swot-head\">\n          <div class=\"swot-icon\">S</div>\n          <div class=\"swot-label\">Strengths</div>\n        </div>\n        <div class=\"swot-item\"><strong>Vietnam's deepest distribution network</strong>38,000 customers, 34 GDP-certified branches across all 63 provinces</div>\n        <div class=\"swot-item\"><strong>World-class manufacturing</strong>EU-GMP & Japan-GMP certified, 8.2 billion units/year capacity</div>\n        <div class=\"swot-item\"><strong>Robust financial health</strong>Gross margin 48%, EPS \u20ab6,308, zero external debt dependency</div>\n      </div>\n      <div class=\"swot-card w\">\n        <div class=\"swot-head\">\n          <div class=\"swot-icon\">W</div>\n          <div class=\"swot-label\">Weaknesses</div>\n        </div>\n        <div class=\"swot-item\"><strong>Weak R&D, reliant on generics</strong>Low 5\u201315% margins, no breakthrough drug pipeline</div>\n        <div class=\"swot-item\"><strong>100% imported raw materials</strong>Dependent on China & India \u2014 major supply chain vulnerability</div>\n        <div class=\"swot-item\"><strong>Rising operational costs</strong>Sales expenses +27.9%, ROA declining to 15.3%</div>\n      </div>\n      <div class=\"swot-card o\">\n        <div class=\"swot-head\">\n          <div class=\"swot-icon\">O</div>\n          <div class=\"swot-label\">Opportunities</div>\n        </div>\n        <div class=\"swot-item\"><strong>Pharma market growing 8\u201310%/year</strong>Aging population, urbanization, rising chronic disease burden</div>\n        <div class=\"swot-item\"><strong>Hospital (ETC) channel expansion</strong>93% insurance coverage, healthcare spend rising to USD 33.8B by 2030</div>\n        <div class=\"swot-item\"><strong>ASEAN export expansion</strong>International certifications unlock Southeast Asian premium segments</div>\n      </div>\n      <div class=\"swot-card t\">\n        <div class=\"swot-head\">\n          <div class=\"swot-icon\">T</div>\n          <div class=\"swot-label\">Threats</div>\n        </div>\n        <div class=\"swot-item\"><strong>Modern pharmacy chains rising</strong>Long Chau, Pharmacity disrupting traditional OTC distribution</div>\n        <div class=\"swot-item\"><strong>Currency volatility & inflation</strong>Import cost pressure, narrowing margins, no hedging instruments</div>\n        <div class=\"swot-item\"><strong>Biotech & AI disruption</strong>Biologics and AI-driven drug discovery threatening generic relevance</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ======= STRENGTHS ======= -->\n  <div id=\"strengths\" class=\"section\">\n    <div class=\"hero\">\n      <div class=\"hero-eyebrow\">Strengths \u2014 Internal Advantages</div>\n      <div class=\"hero-title\">What Makes <span>DHG Competitive</span></div>\n      <div class=\"hero-body\">Three core pillars that have kept DHG as Vietnam's #1 domestic OTC pharmaceutical brand for 29 consecutive years.</div>\n    </div>\n    <div class=\"detail-grid\">\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">01</div>\n          <div>\n            <span class=\"detail-badge badge-green\">Distribution</span>\n            <div class=\"detail-title\">Vietnam's Deepest & Widest Distribution Network</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">DHG operates 34 distribution branches with over 2,800 sales agents, reaching nearly 38,000 customers including hospitals, pharmacies, and 15,244 members of the DHG Pharma Loyal Club. An impressive 32 out of 34 branches have achieved GDP (Good Distribution Practice) certification, ensuring product integrity and safety from manufacturer to end customer. No domestic or international competitor in Vietnam matches this level of national coverage. This network is a structural moat \u2014 built over decades and extremely costly to replicate.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">02</div>\n          <div>\n            <span class=\"detail-badge badge-green\">Manufacturing</span>\n            <div class=\"detail-title\">International-Standard Production Capacity</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">DHG operates two flagship factories certified to EU-GMP and Japan-GMP standards, with a combined annual output of 8.2 billion pharmaceutical units. The recently completed Betalactam facility has achieved EU-GMP certification, opening doors to high-value antibiotic contract manufacturing for export. This dual international certification is rare among Vietnamese pharmaceutical companies and positions DHG as a credible contract manufacturing organization (CMO) for regional pharmaceutical clients. The scale and quality infrastructure underpin DHG's ambition to become a major ASEAN pharmaceutical player.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">03</div>\n          <div>\n            <span class=\"detail-badge badge-green\">Finance</span>\n            <div class=\"detail-title\">Robust Financial Health & Bargaining Power</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">DHG maintains exceptional cash reserves and short-term bank deposits, ensuring complete liquidity self-sufficiency without reliance on costly external credit. This delivered an EPS of \u20ab6,308 in 2025 and funded operations entirely from internal resources. Leveraging 29 years at the top of Vietnam's pharmaceutical market, DHG commands significant bargaining power over global API (Active Pharmaceutical Ingredient) suppliers. As a direct result, gross profit margin expanded meaningfully from 44% to 48% in 2025 \u2014 every 100 VND of revenue now yields 48 VND in gross profit before operational expenses.</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ======= WEAKNESSES ======= -->\n  <div id=\"weaknesses\" class=\"section w-section\">\n    <div class=\"hero\">\n      <div class=\"hero-eyebrow\">Weaknesses \u2014 Internal Challenges</div>\n      <div class=\"hero-title\">Areas That Need <span>Improvement</span></div>\n      <div class=\"hero-body\">Three internal vulnerabilities that must be addressed to sustain DHG's long-term competitiveness and growth trajectory.</div>\n    </div>\n    <div class=\"detail-grid\">\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">01</div>\n          <div>\n            <span class=\"detail-badge badge-red\">R&D</span>\n            <div class=\"detail-title\">Weak R&D Capability & Low Generic Profit Margins</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">DHG primarily manufactures and distributes generic drugs and lacks the capability to independently develop specialized or innovative medicines. Generic drugs carry thin margins of only 5\u201315%, compared to 30\u201350% for branded pharmaceuticals. The company has limited technological research capacity, a shortage of highly qualified pharmaceutical scientists, and relatively low clinical trial infrastructure. Combined with strong competition from multinational firms (DKSH, Sanofi, GSK), DHG struggles to attract top scientific talent. R&D requires substantial investment and carries high risk, placing DHG at a structural disadvantage against global pharmaceutical corporations.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">02</div>\n          <div>\n            <span class=\"detail-badge badge-red\">Supply Chain</span>\n            <div class=\"detail-title\">Complete Dependence on Imported Raw Materials</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">DHG imports virtually all Active Pharmaceutical Ingredients (APIs) from China and India. This creates multiple vulnerability vectors: raw material price fluctuations, global supply chain disruptions, USD/VND exchange rate volatility, and international trade policy shifts. Limited control over input materials fundamentally weakens vertical integration. Maintaining large raw material buffer stocks to protect production continuity simultaneously creates cash flow pressure and storage cost burdens. The US-China biotechnology tensions have already demonstrated how geopolitical risk can cascade rapidly into pharmaceutical supply chains.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">03</div>\n          <div>\n            <span class=\"detail-badge badge-red\">Profitability</span>\n            <div class=\"detail-title\">Operational Costs Growing Faster Than Revenue</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">In 2025, sales expenses surged 27.9% and general & administrative expenses rose 26.7% \u2014 both significantly outpacing revenue growth of 7.8%. Return on Sales (ROS) reached only 16.2%. ROA declined from 18.6% to 15.3%, signaling deteriorating asset utilization efficiency. ROE recovered slightly to 20.7% but remains below the 2023 high of 23.4%. The 100% dividend payout ratio (\u20ab1,307 billion in 2025) adds further pressure on cash flow and reinvestment capacity. The new global minimum tax policy is also compressing retained earnings. If this cost escalation trend continues unchecked, it will impair both reinvestment capability and shareholder value creation.</div>\n      </div>\n    </div>\n    <div class=\"charts-grid\" style=\"margin-top:2rem;\">\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">DHG Profitability Ratios (%)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartRatios\"></canvas></div>\n      </div>\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">Cost Growth vs Revenue Growth (%)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartCosts\"></canvas></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ======= OPPORTUNITIES ======= -->\n  <div id=\"opportunities\" class=\"section\">\n    <div class=\"hero\">\n      <div class=\"hero-eyebrow\">Opportunities \u2014 External Tailwinds</div>\n      <div class=\"hero-title\">Three Growth <span>Waves</span> to Capture</div>\n      <div class=\"hero-body\">Major macro and market forces that DHG is well-positioned to exploit given its current scale, brand, and distribution reach.</div>\n    </div>\n\n    <div class=\"charts-grid\">\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">Vietnam Pharma Market Forecast (USD Billion)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartForecast\"></canvas></div>\n      </div>\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">Key Demographic Drivers (%)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartDemo\"></canvas></div>\n      </div>\n    </div>\n\n    <div class=\"detail-grid\">\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">01</div>\n          <div>\n            <span class=\"detail-badge badge-blue\">Demographics</span>\n            <div class=\"detail-title\">Vietnam Pharmaceutical Market Growth</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">Vietnam's pharmaceutical market reached approximately USD 7 billion in 2025 and is forecast to grow at 8\u201310% CAGR through 2030, reaching USD 12 billion. Population over 60 will reach 20% by 2035, significantly increasing demand for chronic disease treatment. Urban population is expanding at 2.7% annually and the middle class will hit 50 million by 2030 with per capita income doubling rural levels. Non-communicable diseases (diabetes at 7.1% adult prevalence, cardiovascular disease causing 30% of deaths) are creating sustained long-term medication demand. Rising health awareness through social media is boosting the vitamins, supplements, and functional food segments.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">02</div>\n          <div>\n            <span class=\"detail-badge badge-blue\">Hospital Channel</span>\n            <div class=\"detail-title\">Expansion into ETC Channel & High-Value Drugs</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">DHG currently earns 70\u201375% of revenue from the OTC channel, with only 25\u201330% from the ETC (hospital) channel. Vietnam has 93% national health insurance coverage, 10,000+ commune health stations, and total healthcare expenditure projected to rise from USD 18.5B (2022) to USD 33.8B by 2030. This creates an enormous untapped opportunity for DHG to enter prescription drug, injectable, and branded generic hospital segments. Through the Taisho partnership, DHG can access technology transfer to develop and market branded pharmaceuticals with 30\u201350% margins, dramatically improving overall profitability versus current generic margins of 5\u201315%.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">03</div>\n          <div>\n            <span class=\"detail-badge badge-blue\">Export</span>\n            <div class=\"detail-title\">Export Market Expansion & ASEAN Integration</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">DHG already exports to 20+ countries, with a strategic focus on Cambodia, Laos, Myanmar and the Philippines. EU-GMP and Japan-GMP certifications provide a clear and defensible competitive advantage in ASEAN markets that are tightening procurement quality requirements. The 8.2 billion unit factory capacity creates meaningful headroom for international contract manufacturing (CMO) without cannibalizing domestic supply. Vietnam's growing reputation as a quality pharmaceutical manufacturing hub, combined with lower labor costs than European or Japanese competitors, further strengthens DHG's export value proposition.</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ======= THREATS ======= -->\n  <div id=\"threats\" class=\"section t-section\">\n    <div class=\"hero\">\n      <div class=\"hero-eyebrow\">Threats \u2014 External Risks</div>\n      <div class=\"hero-title\">Forces That Could <span>Disrupt</span> DHG</div>\n      <div class=\"hero-body\">Four macroeconomic and industry-level risks requiring active monitoring and mitigation strategies.</div>\n    </div>\n    <div class=\"detail-grid\">\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">01</div>\n          <div>\n            <span class=\"detail-badge badge-amber\">Macroeconomic</span>\n            <div class=\"detail-title\">Inflation & Foreign Exchange Volatility</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">Global and domestic inflation reduces consumer purchasing power, directly impacting the OTC segment as households tighten healthcare spending. USD/VND exchange rate fluctuations increase API import costs and directly compress gross margins. Since DHG sources virtually all raw materials internationally, any adverse currency movement passes through quickly to the cost of goods sold. DHG currently lacks effective financial hedging instruments, leaving the company fully exposed to FX risk. Sustained inflationary pressure could erode the gross margin gains achieved in 2025.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">02</div>\n          <div>\n            <span class=\"detail-badge badge-amber\">Retail Disruption</span>\n            <div class=\"detail-title\">Modern Pharmacy Chains Reshaping Distribution</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">Long Chau, Pharmacity, and An Khang are growing at above 15% CAGR and fundamentally restructuring Vietnam's pharmaceutical retail market. These chains wield stronger supplier bargaining power, demand lower wholesale prices, and use technological and scale advantages to compete directly with DHG's core OTC distribution strength. New government drug bidding regulations in the hospital (ETC) channel are also creating intense price competition and narrowing traditional product margins. DHG's delayed entry into e-commerce and digital distribution channels risks losing relevance among younger, urban consumers. Every month of digital transformation delay widens the competitive gap.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">03</div>\n          <div>\n            <span class=\"detail-badge badge-amber\">Technology</span>\n            <div class=\"detail-title\">Biotech & AI Pharmaceutical Disruption</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">The global pharmaceutical landscape is undergoing significant technological disruption through advanced biotechnology, AI-driven drug discovery, and biologics development \u2014 all driven by multinational pharmaceutical corporations. This represents a fundamental threat: as generics face increasing competition and reduced market share, and as global healthcare procurement standards rise (e.g., EU-GMP requirements expanding in hospital segments), traditional generic products risk becoming commercially obsolete. DHG's current R&D capability cannot realistically compete with the R&D investment levels of Sanofi, GSK, or Pfizer, creating a widening technology gap that worsens over time.</div>\n      </div>\n      <div class=\"detail-card\">\n        <div class=\"detail-head\">\n          <div class=\"detail-num-badge\">04</div>\n          <div>\n            <span class=\"detail-badge badge-amber\">Supply Chain</span>\n            <div class=\"detail-title\">Global API Dependency & Rising Raw Material Costs</div>\n          </div>\n        </div>\n        <div class=\"detail-body\">Vietnamese pharmaceutical companies, including DHG, are highly vulnerable to imported API supply chain disruptions. The US-China biotechnology tensions have demonstrated how geopolitical conflict can rapidly increase costs and restrict access to critical raw materials. Stricter environmental regulations in API-supplying countries are causing supply shortages, forcing businesses to seek alternative suppliers at significantly higher costs while still meeting Japan-GMP quality standards. Large buffer inventory requirements to protect against these disruptions simultaneously create enormous cash flow pressure and storage costs \u2014 a structural cost disadvantage that domestic API producers do not face.</div>\n      </div>\n    </div>\n  </div>\n\n  <!-- ======= RECOMMENDATIONS ======= -->\n  <div id=\"recommendations\" class=\"section\">\n    <div class=\"hero\">\n      <div class=\"hero-eyebrow\">Strategic Recommendations</div>\n      <div class=\"hero-title\">Four Priorities for <span>2025\u20132030</span></div>\n      <div class=\"hero-body\">Actionable strategic directions to consolidate DHG's market leadership and build a sustainable, high-margin pharmaceutical business.</div>\n    </div>\n\n    <div class=\"rec-card\">\n      <div class=\"rec-num\">Recommendation 01 \u2014 R&D & Portfolio Upgrade</div>\n      <div class=\"rec-title\">Enhance R&D Capability Through Taisho Technology Transfer</div>\n      <div class=\"rec-body\">Since DHG lacks the independent capacity for pharmaceutical innovation, the company must strategically deepen its collaboration with Taisho Pharmaceutical. By accelerating direct technology transfer, DHG can mass-produce high-value patented and specialized drugs, effectively diversifying income streams and reducing heavy reliance on low-margin generics. Concurrently, DHG should pursue EU-GMP and Japan-GMP certification across all manufacturing lines while actively diversifying its API supplier base beyond China and India. This addresses the R&D weakness while simultaneously expanding the premium product portfolio \u2014 shifting the revenue mix toward branded pharmaceutical margins of 30\u201350%.</div>\n    </div>\n\n    <div class=\"rec-card\">\n      <div class=\"rec-num\">Recommendation 02 \u2014 Supply Chain Resilience</div>\n      <div class=\"rec-title\">Diversify Import Sources & Build Strategic Supply Buffers</div>\n      <div class=\"rec-body\">To reduce severe API dependency on China and India, DHG should expand its international supplier network across Europe, South Korea, and Southeast Asia, and establish strategic domestic joint ventures to begin localizing raw material production. The company should construct larger strategic warehouses for critical input materials to buffer against global supply disruptions. Financial hedging instruments should be introduced to stabilize input costs against exchange rate volatility. A long-term goal of domestic API manufacturing capability would fundamentally transform DHG's cost structure and supply chain risk profile, moving toward true vertical integration.</div>\n    </div>\n\n    <div class=\"rec-card\">\n      <div class=\"rec-num\">Recommendation 03 \u2014 Financial Efficiency</div>\n      <div class=\"rec-title\">Optimize Operational Costs & Improve Capital Allocation</div>\n      <div class=\"rec-body\">DHG must implement rigorous cost management to address the growing imbalance between revenue and expense growth. Core actions include: digitalizing administrative and sales processes to systematically reduce overhead; shifting from the rigid 100% dividend payout policy to a flexible dividend model that frees capital for reinvestment; and building a long-term tax optimization strategy to adapt to the global minimum tax framework. Concrete KPIs should be set to recover ROA back to historical levels (18%+), and cost approval thresholds tightened for sales and marketing spend where ROI is unclear.</div>\n    </div>\n\n    <div class=\"rec-card\">\n      <div class=\"rec-num\">Recommendation 04 \u2014 Market Expansion</div>\n      <div class=\"rec-title\">Capitalize on Urban Growth & Chronic Disease Portfolios</div>\n      <div class=\"rec-body\">DHG's strong brand recognition positions it to aggressively expand commercial presence in Vietnam's highest-growth urban markets: Ho Chi Minh City, Hanoi, Da Nang, and Can Tho. Marketing and distribution strategies should specifically target the emerging middle class, which is demonstrating rising healthcare awareness and higher willingness-to-pay for quality branded products. Operationally, DHG should deepen its focus on chronic disease treatment portfolios \u2014 diabetes, cardiovascular, respiratory \u2014 while expanding vitamins and functional food lines to capture the booming preventive healthcare trend. Increased R&D budget allocation for long-term disease management products is essential to sustaining this shift.</div>\n    </div>\n\n    <div class=\"divider\"></div>\n    <div class=\"charts-grid\">\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">Strategic Priority Matrix</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartStrategy\"></canvas></div>\n      </div>\n      <div class=\"chart-card\">\n        <div class=\"chart-title\">Generic vs Branded Margin Comparison (%)</div>\n        <div class=\"chart-wrap\"><canvas id=\"chartMargins\"></canvas></div>\n      </div>\n    </div>\n\n    <div class=\"footer\">\n      <strong>DHG Pharma SWOT Analysis 2025 \u00b7 Business English 3</strong><br>\n      Dang Nguyen Vinh Tuong (10625077) \u00b7 Le Hien Tri (10325024) \u00b7 Nguyen Truong Thinh (1065090) \u00b7 Nguyen Minh Tuan (10625055)<br>\n      Instructor: Nguyen Thanh Duoc \u00b7 Academic Year 2025\n    </div>\n  </div>\n\n</div><!-- /page -->\n\n<script>\n// ---- Navigation ----\nfunction showSection(id, btn) {\n  document.querySelectorAll('.section').forEach(s => s.classList.remove('visible'));\n  document.querySelectorAll('.nav-btn').forEach(b => b.classList.remove('active'));\n  document.getElementById(id).classList.add('visible');\n  btn.classList.add('active');\n  window.scrollTo({ top: 0, behavior: 'smooth' });\n  if (id === 'weaknesses' && !window._chartsWeakness) { buildWeaknessCharts(); window._chartsWeakness = true; }\n  if (id === 'opportunities' && !window._chartsOpportunity) { buildOpportunityCharts(); window._chartsOpportunity = true; }\n  if (id === 'recommendations' && !window._chartsRec) { buildRecCharts(); window._chartsRec = true; }\n}\n\n// ---- Brand colors ----\nconst G1 = '#0D7A4E', G2 = '#1A9960', G3 = '#A8DECA', G4 = '#D6F0E4';\nconst R1 = '#C41E3A', GOLD = '#E8A020';\nconst GRAY = '#8A9099';\n\nconst defaults = {\n  font: { family: \"-apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif\", size: 11 },\n  color: '#5A6472'\n};\nChart.defaults.font = defaults.font;\nChart.defaults.color = defaults.color;\n\nfunction baseOpts(extra) {\n  return Object.assign({\n    responsive: true, maintainAspectRatio: false,\n    plugins: { legend: { display: false }, tooltip: { callbacks: {} } },\n    scales: {}\n  }, extra);\n}\n\n// ---- Overview charts ----\nnew Chart('chartMarket', {\n  type: 'bar',\n  data: {\n    labels: ['2022', '2023', '2024', '2025', '2026F', '2027F', '2028F'],\n    datasets: [{\n      data: [5.2, 5.9, 6.5, 7.0, 7.7, 8.6, 12.0],\n      backgroundColor: ['#A8DECA','#A8DECA','#A8DECA','#0D7A4E','#D6F0E4','#D6F0E4','#D6F0E4'],\n      borderRadius: 5, borderSkipped: false\n    }]\n  },\n  options: baseOpts({\n    plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => ' USD ' + ctx.parsed.y + 'B' } } },\n    scales: { y: { beginAtZero: true, grid: { color: '#E2E8E4' }, ticks: { callback: v => '$' + v + 'B' } }, x: { grid: { display: false } } }\n  })\n});\n\nnew Chart('chartRevenue', {\n  type: 'bar',\n  data: {\n    labels: ['2022', '2023', '2024', '2025'],\n    datasets: [\n      { label: 'Net Revenue', data: [4820, 5200, 5740, 6140], backgroundColor: G1, borderRadius: 5, borderSkipped: false },\n      { label: 'Net Profit', data: [640, 720, 778, 852], backgroundColor: G3, borderRadius: 5, borderSkipped: false }\n    ]\n  },\n  options: baseOpts({\n    plugins: { legend: { display: true, position: 'top' }, tooltip: { callbacks: { label: ctx => ' \u20ab' + ctx.parsed.y + 'B' } } },\n    scales: { y: { beginAtZero: true, grid: { color: '#E2E8E4' }, ticks: { callback: v => '\u20ab' + v } }, x: { grid: { display: false } } }\n  })\n});\n\nnew Chart('chartMargin', {\n  type: 'line',\n  data: {\n    labels: ['2022', '2023', '2024', '2025'],\n    datasets: [{\n      data: [41, 43, 44, 48],\n      borderColor: G1, backgroundColor: G4, fill: true,\n      tension: 0.4, pointBackgroundColor: G1, pointRadius: 5\n    }]\n  },\n  options: baseOpts({\n    plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => ' ' + ctx.parsed.y + '%' } } },\n    scales: { y: { min: 35, max: 55, grid: { color: '#E2E8E4' }, ticks: { callback: v => v + '%' } }, x: { grid: { display: false } } }\n  })\n});\n\nnew Chart('chartChannel', {\n  type: 'doughnut',\n  data: {\n    labels: ['OTC / Pharmacy', 'ETC / Hospital', 'Export'],\n    datasets: [{ data: [72, 21, 7], backgroundColor: [G1, G2, G3], borderWidth: 0, hoverOffset: 8 }]\n  },\n  options: {\n    responsive: true, maintainAspectRatio: false,\n    plugins: { legend: { display: true, position: 'bottom' }, tooltip: { callbacks: { label: ctx => ' ' + ctx.parsed + '%' } } },\n    cutout: '60%'\n  }\n});\n\n// ---- Weakness charts (lazy) ----\nfunction buildWeaknessCharts() {\n  new Chart('chartRatios', {\n    type: 'line',\n    data: {\n      labels: ['2022', '2023', '2024', '2025'],\n      datasets: [\n        { label: 'ROE %', data: [21, 23.4, 17.4, 20.7], borderColor: G1, backgroundColor: 'transparent', tension: 0.4, pointBackgroundColor: G1, pointRadius: 4 },\n        { label: 'ROA %', data: [17, 18.6, 16.2, 15.3], borderColor: R1, backgroundColor: 'transparent', tension: 0.4, pointBackgroundColor: R1, pointRadius: 4 },\n        { label: 'ROS %', data: [14, 15.8, 16.0, 16.2], borderColor: GOLD, backgroundColor: 'transparent', tension: 0.4, pointBackgroundColor: GOLD, pointRadius: 4 }\n      ]\n    },\n    options: baseOpts({\n      plugins: { legend: { display: true, position: 'top' }, tooltip: { callbacks: { label: ctx => ' ' + ctx.dataset.label + ' ' + ctx.parsed.y + '%' } } },\n      scales: { y: { grid: { color: '#E2E8E4' }, ticks: { callback: v => v + '%' } }, x: { grid: { display: false } } }\n    })\n  });\n\n  new Chart('chartCosts', {\n    type: 'bar',\n    data: {\n      labels: ['Net Revenue', 'Sales Expense', 'Admin Expense'],\n      datasets: [{ data: [7.8, 27.9, 26.7], backgroundColor: [G1, R1, '#E8602A'], borderRadius: 5, borderSkipped: false }]\n    },\n    options: baseOpts({\n      plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => ' +' + ctx.parsed.y + '%' } } },\n      scales: { y: { beginAtZero: true, grid: { color: '#E2E8E4' }, ticks: { callback: v => '+' + v + '%' } }, x: { grid: { display: false } } }\n    })\n  });\n}\n\n// ---- Opportunity charts (lazy) ----\nfunction buildOpportunityCharts() {\n  new Chart('chartForecast', {\n    type: 'bar',\n    data: {\n      labels: ['2022', '2023', '2024', '2025', '2026F', '2027F', '2028F'],\n      datasets: [{\n        data: [5.2, 5.9, 6.5, 7.0, 7.7, 8.6, 12.0],\n        backgroundColor: [GRAY,GRAY,GRAY,G1,'#A8DECA','#A8DECA','#1A9960'],\n        borderRadius: 5, borderSkipped: false\n      }]\n    },\n    options: baseOpts({\n      plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => ' $' + ctx.parsed.y + 'B' } } },\n      scales: { y: { beginAtZero: true, grid: { color: '#E2E8E4' }, ticks: { callback: v => '$' + v + 'B' } }, x: { grid: { display: false } } }\n    })\n  });\n\n  new Chart('chartDemo', {\n    type: 'bar',\n    data: {\n      labels: ['Urban pop 2025', 'Urban pop 2030', 'Elderly 60+ 2035', 'Insurance coverage', 'Diabetes rate'],\n      datasets: [{\n        data: [45, 50, 20, 93, 7.1],\n        backgroundColor: [G2, G1, '#E8A020', G1, R1],\n        borderRadius: 5, borderSkipped: false\n      }]\n    },\n    options: baseOpts({\n      indexAxis: 'y',\n      plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => ' ' + ctx.parsed.x + '%' } } },\n      scales: { x: { max: 100, grid: { color: '#E2E8E4' }, ticks: { callback: v => v + '%' } }, y: { grid: { display: false } } }\n    })\n  });\n}\n\n// ---- Recommendation charts (lazy) ----\nfunction buildRecCharts() {\n  new Chart('chartStrategy', {\n    type: 'radar',\n    data: {\n      labels: ['R&D Upgrade', 'Supply Chain', 'Cost Control', 'Market Expansion', 'Digital Transform', 'Export Growth'],\n      datasets: [\n        { label: 'Current', data: [2, 3, 3, 7, 3, 5], borderColor: GRAY, backgroundColor: 'rgba(138,144,153,0.1)', pointBackgroundColor: GRAY },\n        { label: 'Target', data: [6, 7, 7, 9, 7, 8], borderColor: G1, backgroundColor: 'rgba(13,122,78,0.12)', pointBackgroundColor: G1 }\n      ]\n    },\n    options: {\n      responsive: true, maintainAspectRatio: false,\n      plugins: { legend: { display: true, position: 'top' } },\n      scales: { r: { min: 0, max: 10, ticks: { stepSize: 2 }, grid: { color: '#E2E8E4' }, pointLabels: { font: { size: 11 } } } }\n    }\n  });\n\n  new Chart('chartMargins', {\n    type: 'bar',\n    data: {\n      labels: ['Generic (low)', 'Generic (high)', 'Branded Generic', 'Specialty / Patented'],\n      datasets: [{\n        data: [5, 15, 30, 50],\n        backgroundColor: [R1, '#E8602A', G2, G1],\n        borderRadius: 6, borderSkipped: false\n      }]\n    },\n    options: baseOpts({\n      plugins: { legend: { display: false }, tooltip: { callbacks: { label: ctx => ' ' + ctx.parsed.y + '% margin' } } },\n      scales: { y: { beginAtZero: true, max: 60, grid: { color: '#E2E8E4' }, ticks: { callback: v => v + '%' } }, x: { grid: { display: false } } }\n    })\n  });\n}\n</script>\n</body>\n</html>\n"

components.html(HTML, height=950, scrolling=True)
